import "server-only";

import { Axiom } from "@axiomhq/js";

const axiom = new Axiom({ token: process.env.AXIOM_TOKEN });

export async function logAxiomEvent(event: Record<string, unknown>) {
  if (!process.env.AXIOM_DATASET) throw new Error("AXIOM_DATASET is required");
  await axiom.ingest(process.env.AXIOM_DATASET, [{ ...event, timestamp: new Date().toISOString() }]);
}

import { NextResponse } from "next/server";

import { logAxiomEvent } from "@/lib/axiom/logger";

export async function POST() {
  await logAxiomEvent({ event: "stackfoundry.smoke", source: "registry" });
  return NextResponse.json({ ok: true });
}

const deployChecks = [
  "Create the vendor project and add production env vars",
  "Run the included smoke route after deploy",
  "Document alerting, retries, and rollback behavior",
];

export default function AxiomLoggingPage() {
  return (
    <main className="flex flex-col gap-6 p-6">
      <div>
        <h1 className="text-2xl font-semibold">Axiom Logging</h1>
        <p className="text-muted-foreground">Structured logs for requests, jobs, webhooks, and operator actions.</p>
      </div>
      <div className="grid gap-3">
        {deployChecks.map((check) => (
          <div key={check} className="rounded-lg border p-4 text-sm">{check}</div>
        ))}
      </div>
    </main>
  );
}
